const resultados = [];

// Función auxiliar para normalizar nombres y evitar fallos en BD o JSON
function normalizarTexto(valor) {
  if (valor === null || valor === undefined) return null;

  if (typeof valor === 'string') {
    let limpio = valor
      // Elimina comillas simples/apóstrofes (la principal causa de error con "D'Angelo")
      .replace(/['`´]/g, '')
      // Elimina comas (por si llega un error de tipeo tipo "Sergio, D Angelo")
      .replace(/,/g, '')
      // Elimina punto y coma y comillas dobles (prevención de inyección o saltos en JSON)
      .replace(/[";]/g, '')
      // Limpia espacios dobles y espacios al inicio/final
      .replace(/\s+/g, ' ')
      .trim();

    // Si la cadena queda como 'null' (texto), siempre lo devolvemos como literal null (sin comillas)
    if (limpio.toLowerCase() === 'null' || limpio === '') {
      return null;
    }

    return limpio;
  }

  return valor;
}

// Función auxiliar para normalizar el número de personas
function normalizarNumeroPersonas(valor) {
  if (valor === null || valor === undefined) return 1;

  let numero;
  if (typeof valor === 'number') {
    numero = valor;
  } else if (typeof valor === 'string') {
    const limpio = valor.toString().replace(/[^\d.,]/g, '').replace(',', '.');
    numero = parseFloat(limpio);
  } else {
    numero = Number(valor);
  }

  if (isNaN(numero) || !isFinite(numero) || numero <= 0) {
    return 1; 
  }

  return Math.max(1, Math.round(numero));
}

for (const item of items) {
  let resultadoFinal = null;
  let errorLog = null;

  const raw = item.json?.reservacion; 

  if (!raw) {
    resultados.push({ json: { error: "Input vacío" } });
    continue;
  }

  if (typeof raw === 'object') {
    resultadoFinal = raw;
  } else {
    const clean = String(raw).replace(/```json|```/g, '').trim();

    try {
      resultadoFinal = JSON.parse(clean);
    } catch (e1) {
      try {
        const sanitized = clean
          .replace(/\n/g, "\\n")
          .replace(/\r/g, "\\r")
          .replace(/\t/g, "\\t");

        resultadoFinal = JSON.parse(sanitized);
      } catch (e2) {
        errorLog = e1.message;
      }
    }
  }

  if (resultadoFinal) {
    // 1. Normalizamos Personas
    if (resultadoFinal.hasOwnProperty('personas')) {
      resultadoFinal.personas = normalizarNumeroPersonas(resultadoFinal.personas);
    }
    const camposPersonas = ['numero_personas', 'cantidad_personas', 'personas', 'pax', 'guests'];
    for (const campo of camposPersonas) {
      if (resultadoFinal.hasOwnProperty(campo)) {
        resultadoFinal[campo] = normalizarNumeroPersonas(resultadoFinal[campo]);
        break; 
      }
    }

    // 2. Normalizamos el Nombre Completo (Blindaje)
    if (resultadoFinal.hasOwnProperty('nombre_completo')) {
      resultadoFinal.nombre_completo = normalizarTexto(resultadoFinal.nombre_completo);
    }

    // Si tuvieras un esquema donde el campo principal falla y necesitas un fallback:
    // resultadoFinal.nombre_completo = resultadoFinal.nombre_completo || resultadoFinal.first_name || null;

    resultados.push({ json: resultadoFinal });
  } else {
    resultados.push({ 
      json: { 
        error: "No se pudo parsear el JSON",
        detalles: errorLog,
        input_recibido: raw 
      } 
    });
  }
}

return resultados;

