// n8n Code node (JavaScript)

// Reglas de salida única (prioridad):
// 1) CIERRE: Lunes ("Día") o Ventana ("Horario") -> { mensaje: "Cerrado", motivo: "...", ahora: "..." }
// 2) FORMATO HORA: Solo bloques de :00 o :30 -> { mensaje: "FormatoHora", detalle: "Solo bloques de 30 min", ahora: "..." }
// 3) Pasado/ahora: fecha/hora <= ahora -> { mensaje: "Pasado", ahora: "<...>" }
// 4) Futura: fecha/hora > ahora + 3 meses -> { mensaje: "Futuro", ahora: "<...>" }
// 5) Muy próxima: (ahora, ahora + 60 min) -> { mensaje: "Cercano", ahora: "<...>" }
// 6) Válida: devolver input original + NUEVO CAMPO 'dia_semana'.

const OFFSET_TZ_MIN = 3 * 60;    // Argentina UTC-3
const WINDOW_MIN = 60;           // "Muy próxima" = 60 minutos
const MAX_FUTURE_MONTHS = 3;     // Límite de meses en el futuro

const DIAS_SEMANA = ['Domingo', 'Lunes', 'Martes', 'Miércoles', 'Jueves', 'Viernes', 'Sábado'];

const CLOSED_WINDOWS = [
  { startMin: 16 * 60,        endMin: 18 * 60 },       // 16:00–18:00
  { startMin: 0,              endMin: 10 * 60 + 30 },  // 00:00–10:30
];

// --- FUNCIONES HELPER ---

function parseDateParts(fechaStr) {
  const clean = String(fechaStr || '').trim().replace(/-/g, '/');
  const [y, m, d] = clean.split('/').map(n => parseInt(n, 10));
  if (![y, m, d].every(Number.isFinite)) return null;
  return { y, m, d };
}

function parseTimeParts(horaStr) {
  const parts = String(horaStr || '').trim().split(':');
  const hh = parseInt(parts[0], 10);
  const mm = parseInt(parts[1] ?? '0', 10);
  if (![hh, mm].every(Number.isFinite)) return null;
  return { hh, mm };
}

// [NUEVO] Valida si los minutos son 00 o 30
function isValidMinuteBlock(horaStr) {
  const t = parseTimeParts(horaStr);
  if (!t) return false;
  return t.mm === 0 || t.mm === 30;
}

function toUtcMsFromARG(fechaStr, horaStr) {
  const d = parseDateParts(fechaStr);
  const t = parseTimeParts(horaStr);
  if (!d || !t) return NaN;
  return Date.UTC(d.y, d.m - 1, d.d, t.hh + Math.floor(OFFSET_TZ_MIN / 60), t.mm, 0, 0);
}

function getDiaSemanaNombre(fechaStr) {
  const d = parseDateParts(fechaStr);
  if (!d) return null;
  const dow = new Date(Date.UTC(d.y, d.m - 1, d.d)).getUTCDay(); 
  return DIAS_SEMANA[dow];
}

function isWithinClosedWindow(horaStr) {
  const mins = (t => t ? t.hh * 60 + t.mm : null)(parseTimeParts(horaStr));
  if (mins == null) return false;
  return CLOSED_WINDOWS.some(w => mins >= w.startMin && mins < w.endMin);
}

function pad2(n){ return n < 10 ? '0' + n : '' + n; }

function nowARGString() {
  const d = new Date(Date.now() - OFFSET_TZ_MIN * 60 * 1000);
  return `${d.getUTCFullYear()}-${pad2(d.getUTCMonth() + 1)}-${pad2(d.getUTCDate())} ${pad2(d.getUTCHours())}:${pad2(d.getUTCMinutes())}`;
}

// --- LÓGICA PRINCIPAL ---

const items = await $input.all();
const nowUtcMs = Date.now();
const soonLimitUtcMs = nowUtcMs + WINDOW_MIN * 60 * 1000;
const ahora = nowARGString();

const futureLimitDate = new Date();
futureLimitDate.setMonth(futureLimitDate.getMonth() + MAX_FUTURE_MONTHS);
const futureLimitUtcMs = futureLimitDate.getTime();

let motivoCierre = null; 
let hasInvalidBlock = false;
let hasPastOrNow = false;
let hasFuture = false;
let hasSoon = false;

for (const item of items) {
  const { fecha, hora } = item.json || {};
  const nombreDia = getDiaSemanaNombre(fecha);

  if (item.json) item.json.dia_semana = nombreDia;

  // Regla 1: CIERRE
  if (nombreDia === 'Lunes') { motivoCierre = 'Lunes'; break; }
  if (isWithinClosedWindow(hora)) { motivoCierre = 'Horario'; break; }

  // Regla 2: [NUEVA] Validación de bloques de 30 min
  if (!isValidMinuteBlock(hora)) {
    hasInvalidBlock = true;
    break;
  }

  const targetUtcMs = toUtcMsFromARG(fecha, hora);

  // Regla 3: Pasado
  if (!Number.isFinite(targetUtcMs) || targetUtcMs <= nowUtcMs) { hasPastOrNow = true; break; }

  // Regla 4: Futura
  if (targetUtcMs > futureLimitUtcMs) { hasFuture = true; break; }

  // Regla 5: Muy próxima
  if (targetUtcMs < soonLimitUtcMs) { hasSoon = true; }
}

// Retornos por prioridad
if (motivoCierre) return [{ json: { mensaje: 'Cerrado', motivo: motivoCierre, ahora } }];
if (hasInvalidBlock) return [{ json: { mensaje: 'FormatoHora', detalle: 'Solo se aceptan bloques de 00 o 30 minutos', ahora } }];
if (hasPastOrNow) return [{ json: { mensaje: 'Pasado', ahora } }];
if (hasFuture) return [{ json: { mensaje: 'Futuro', ahora } }];
if (hasSoon) return [{ json: { mensaje: 'Cercano', ahora } }];

return items;

