  return DIAS_SEMANA[dow];
}

function isWithinClosedWindow(horaStr) {
  const mins = (t => t ? t.hh * 60 + t.mm : null)(parseTimeParts(horaStr));
  if (mins == null) return false;
  return CLOSED_WINDOWS.some(w => mins >= w.startMin && mins < w.endMin);
}

