// Configuración: Usamos el nombre oficial de la zona horaria (IANA)
// Esto maneja automáticamente cambios de horario de verano/invierno si ocurren.
const timeZone = 'America/Argentina/Buenos_Aires';

for (const item of $input.all()) {

  const fechaRaw = item.json.fecha_reservacion; // "2025-12-04T00:00:00..."
  const horaRaw = item.json.hora_reservacion;   // "22:00:00"

  if (fechaRaw && horaRaw) {
    // -----------------------------------------------------------
    // PASO 1: Normalizar la Fecha Objetivo (Reserva)
    // -----------------------------------------------------------
    // Extraemos YYYY-MM-DD
    const fechaSolo = fechaRaw.split('T')[0];

    // Creamos una fecha "ficticia" en UTC con los datos de la reserva
    // Le agregamos la 'Z' para forzar a JS a creer que es UTC.
    // Hacemos esto para tener un punto de comparación matemático neutro.
    const targetDateISO = `${fechaSolo}T${horaRaw}Z`; 
    const targetDate = new Date(targetDateISO);

    // -----------------------------------------------------------
    // PASO 2: Obtener la Hora Actual en Argentina Dinámicamente
    // -----------------------------------------------------------
    const now = new Date();

    // Usamos Intl para descomponer la hora actual según la zona horaria de Argentina
    const formatter = new Intl.DateTimeFormat('en-US', {
      timeZone: timeZone,
      year: 'numeric', month: '2-digit', day: '2-digit',
      hour: '2-digit', minute: '2-digit', second: '2-digit',
      hour12: false
    });

    // Extraemos las partes (año, mes, dia, hora...) de la hora actual argentina
    const parts = formatter.formatToParts(now);
    const mapping = {};
    parts.forEach(p => mapping[p.type] = p.value);

    // Reconstruimos la fecha actual de Argentina como si fuera UTC (para que coincida con el Paso 1)
    // Formato: YYYY-MM-DDTHH:mm:ssZ
    const nowArgISO = `${mapping.year}-${mapping.month}-${mapping.day}T${mapping.hour}:${mapping.minute}:${mapping.second}Z`;
    const nowArgDate = new Date(nowArgISO);

    // -----------------------------------------------------------
    // PASO 3: Calcular Diferencia
    // -----------------------------------------------------------
    // Al restar dos objetos Date, obtenemos milisegundos
    const diffMs = targetDate - nowArgDate;
    const diferenciaHoras = diffMs / (1000 * 60 * 60);

    // -----------------------------------------------------------
    // PASO 4: Tu Lógica de Negocio
    // -----------------------------------------------------------

    // Si la diferencia es positiva (futuro) Y es menor a 1 hora
    if (diferenciaHoras > 0 && diferenciaHoras < 1) {
      item.json.mensaje_validacion = "Todo es correcto (Menor a 1h)";
      item.json.procede_actualizacion = "Sí";

    } else if (diferenciaHoras <= 0) {
      item.json.mensaje_validacion = "No es posible de confirmar (La reservación ya pasó: "+targetDateISO+")";
      item.json.procede_actualizacion = "No";

    } else {
      item.json.mensaje_validacion = "Informa al usuario que la reserva está asegurada pero la confirmación aún no es posible (Falta más de 1h).";
      item.json.procede_actualizacion = "No";
    }

    // Debug (opcional)
    item.json.debug_target = targetDateISO;
    item.json.debug_now_arg = nowArgISO;
    item.json.debug_diff = diferenciaHoras;

  } else {
    item.json.mensaje_validacion = "Error: Faltan datos";
    item.json.procede_actualizacion = "No";
  }
}

return $input.all();

